function removeDuplicates(a) {
  if (a.length === 0) return 0;
  let w = 1;
  for (let i = 1; i < a.length; i++) {
    if (a[i] !== a[w - 1]) {
      a[w] = a[i];
      w++;
    }
  }
  return w;
}

tests:
let a = [1, 1, 2];
if (removeDuplicates(a) !== 2) throw new Error('m');
if (JSON.stringify(a.slice(0, 2)) !== JSON.stringify([1, 2])) throw new Error('front');
let b = [0, 0, 1, 1, 1, 2, 2, 3, 3, 4];
if (removeDuplicates(b) !== 5) throw new Error('m2');
if (JSON.stringify(b.slice(0, 5)) !== JSON.stringify([0, 1, 2, 3, 4])) throw new Error('front2');
if (removeDuplicates([7]) !== 1) throw new Error('single');
if (removeDuplicates([]) !== 0) throw new Error('empty');

