solution:
function removeElement(a, val) {
  let w = 0;
  for (let i = 0; i < a.length; i++) {
    if (a[i] !== val) {
      a[w] = a[i];
      w++;
    }
  }
  return w;
}

tests:
let a = [3, 2, 2, 3];
if (removeElement(a, 3) !== 2) throw new Error('m');
if (JSON.stringify(a.slice(0, 2)) !== JSON.stringify([2, 2])) throw new Error('front');
let b = [0, 1, 2, 2, 3, 0, 4, 2];
if (removeElement(b, 2) !== 5) throw new Error('m2');
if (JSON.stringify(b.slice(0, 5)) !== JSON.stringify([0, 1, 3, 0, 4])) throw new Error('front2');
if (removeElement([], 1) !== 0) throw new Error('empty');
if (removeElement([1, 1, 1], 1) !== 0) throw new Error('all');
